CREATE TABLE IF NOT EXISTS users (id BIGINT PRIMARY KEY AUTO_INCREMENT, name VARCHAR(160), email VARCHAR(180) UNIQUE, mobile VARCHAR(30) UNIQUE, password_hash VARCHAR(255), role VARCHAR(40) DEFAULT 'USER', status VARCHAR(40) DEFAULT 'ACTIVE', image_url TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS restaurants (id BIGINT PRIMARY KEY AUTO_INCREMENT, owner_id BIGINT NULL, name VARCHAR(180) NOT NULL, slug VARCHAR(220) UNIQUE, description TEXT, image_url TEXT, address TEXT, latitude DECIMAL(10,7), longitude DECIMAL(10,7), rating DECIMAL(3,2) DEFAULT 4.5, delivery_radius_km DECIMAL(8,2) DEFAULT 8, minimum_order DECIMAL(10,2) DEFAULT 99, is_open BOOLEAN DEFAULT TRUE, verification_status VARCHAR(40) DEFAULT 'PENDING', visibility_status VARCHAR(40) DEFAULT 'VISIBLE', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS categories (id BIGINT PRIMARY KEY AUTO_INCREMENT, name VARCHAR(120) NOT NULL, slug VARCHAR(160) UNIQUE, image_url TEXT, parent_id BIGINT NULL, active BOOLEAN DEFAULT TRUE, sort_order INT DEFAULT 0);
CREATE TABLE IF NOT EXISTS brands (id BIGINT PRIMARY KEY AUTO_INCREMENT, name VARCHAR(120) NOT NULL, slug VARCHAR(160) UNIQUE, image_url TEXT, active BOOLEAN DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS products (id BIGINT PRIMARY KEY AUTO_INCREMENT, restaurant_id BIGINT NULL, category_id BIGINT NULL, brand_id BIGINT NULL, name VARCHAR(180) NOT NULL, slug VARCHAR(220) UNIQUE, description TEXT, image_url TEXT, price DECIMAL(10,2) NOT NULL DEFAULT 0, discount_price DECIMAL(10,2), veg BOOLEAN DEFAULT TRUE, available BOOLEAN DEFAULT TRUE, rating DECIMAL(3,2) DEFAULT 4.4, stock INT DEFAULT 100, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS product_customization_groups (id BIGINT PRIMARY KEY AUTO_INCREMENT, product_id BIGINT NOT NULL, name VARCHAR(120), selection_type VARCHAR(30) DEFAULT 'SINGLE', min_select INT DEFAULT 0, max_select INT DEFAULT 1);
CREATE TABLE IF NOT EXISTS product_customization_options (id BIGINT PRIMARY KEY AUTO_INCREMENT, group_id BIGINT NOT NULL, name VARCHAR(120), price DECIMAL(10,2) DEFAULT 0, active BOOLEAN DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS carts (id BIGINT PRIMARY KEY AUTO_INCREMENT, user_id BIGINT NOT NULL, restaurant_id BIGINT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS cart_items (id BIGINT PRIMARY KEY AUTO_INCREMENT, cart_id BIGINT NOT NULL, product_id BIGINT NOT NULL, quantity INT DEFAULT 1, unit_price DECIMAL(10,2) DEFAULT 0, customizations JSON NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS addresses (id BIGINT PRIMARY KEY AUTO_INCREMENT, user_id BIGINT NOT NULL, label VARCHAR(80), name VARCHAR(160), phone VARCHAR(30), line1 TEXT, line2 TEXT, city VARCHAR(100), state VARCHAR(100), pincode VARCHAR(20), latitude DECIMAL(10,7), longitude DECIMAL(10,7), is_default BOOLEAN DEFAULT FALSE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS orders (id BIGINT PRIMARY KEY AUTO_INCREMENT, user_id BIGINT NOT NULL, restaurant_id BIGINT NULL, driver_id BIGINT NULL, slug VARCHAR(80) UNIQUE, status VARCHAR(50) DEFAULT 'PLACED', payment_type VARCHAR(30) DEFAULT 'COD', payment_status VARCHAR(30) DEFAULT 'PENDING', subtotal DECIMAL(10,2) DEFAULT 0, delivery_fee DECIMAL(10,2) DEFAULT 0, platform_fee DECIMAL(10,2) DEFAULT 0, discount DECIMAL(10,2) DEFAULT 0, total DECIMAL(10,2) DEFAULT 0, address_snapshot JSON NULL, cancel_reason TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS order_items (id BIGINT PRIMARY KEY AUTO_INCREMENT, order_id BIGINT NOT NULL, product_id BIGINT NULL, name VARCHAR(180), quantity INT DEFAULT 1, unit_price DECIMAL(10,2) DEFAULT 0, total DECIMAL(10,2) DEFAULT 0, customizations JSON NULL);
CREATE TABLE IF NOT EXISTS payment_transactions (id BIGINT PRIMARY KEY AUTO_INCREMENT, order_id BIGINT NULL, user_id BIGINT NULL, provider VARCHAR(30) DEFAULT 'RAZORPAY', provider_order_id VARCHAR(120), provider_payment_id VARCHAR(120), provider_signature VARCHAR(255), amount DECIMAL(10,2) DEFAULT 0, currency VARCHAR(10) DEFAULT 'INR', status VARCHAR(40) DEFAULT 'CREATED', raw_payload JSON NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS offers (id BIGINT PRIMARY KEY AUTO_INCREMENT, title VARCHAR(180), code VARCHAR(60), type VARCHAR(60), discount_type VARCHAR(40) DEFAULT 'FLAT', discount_value DECIMAL(10,2) DEFAULT 0, min_order DECIMAL(10,2) DEFAULT 0, image_url TEXT, active BOOLEAN DEFAULT TRUE, starts_at DATETIME NULL, ends_at DATETIME NULL);
CREATE TABLE IF NOT EXISTS coupons (id BIGINT PRIMARY KEY AUTO_INCREMENT, code VARCHAR(60) UNIQUE, discount_type VARCHAR(40) DEFAULT 'FLAT', discount_value DECIMAL(10,2) DEFAULT 0, min_order DECIMAL(10,2) DEFAULT 0, max_discount DECIMAL(10,2), active BOOLEAN DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS notifications (id BIGINT PRIMARY KEY AUTO_INCREMENT, user_id BIGINT NULL, role VARCHAR(40) NULL, title VARCHAR(180), message TEXT, type VARCHAR(60), is_read BOOLEAN DEFAULT FALSE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS reviews (id BIGINT PRIMARY KEY AUTO_INCREMENT, user_id BIGINT, order_id BIGINT NULL, restaurant_id BIGINT NULL, product_id BIGINT NULL, rating INT, comment TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS support_tickets (id BIGINT PRIMARY KEY AUTO_INCREMENT, user_id BIGINT NULL, subject VARCHAR(200), message TEXT, status VARCHAR(40) DEFAULT 'OPEN', priority VARCHAR(40) DEFAULT 'NORMAL', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS delivery_locations (id BIGINT PRIMARY KEY AUTO_INCREMENT, order_id BIGINT NULL, driver_id BIGINT NULL, latitude DECIMAL(10,7), longitude DECIMAL(10,7), heading DECIMAL(10,2), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS settings (setting_key VARCHAR(100) PRIMARY KEY, setting_value JSON, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
